'use strict';

function assertEl(sel) {
  const el = document.querySelector(sel);
  if (!el) console.error(`[async-ui] elemento não encontrado: ${sel}`);
  return el;
}

const btnLoad = assertEl('#load');
const btnCancel = assertEl('#cancel');
const elStatus = assertEl('#status');
const elSpinner = assertEl('#spinner');
const elOut = assertEl('#out');

const hasDom = Boolean(btnLoad && btnCancel && elStatus && elSpinner && elOut);

// Estado
let currentJobId = 0;     // identifica a operação mais recente
let currentTimerId = null; // para cancelar setTimeout

function setUi(state, payload) {
  if (!hasDom) return;

  elStatus.textContent = state;
  elSpinner.style.display = (state === 'loading') ? 'block' : 'none';

  if (state === 'idle') {
    elOut.textContent = '—';
  }

  if (state === 'success') {
    elOut.textContent = JSON.stringify(payload, null, 2);
  }

  if (state === 'error') {
    elOut.textContent = String(payload?.message ?? payload ?? 'erro');
  }
}

function cancelCurrent() {
  if (currentTimerId !== null) {
    clearTimeout(currentTimerId);
    currentTimerId = null;
  }
}

function fakeRequest(jobId) {
  // Simula latência e falha ocasional
  const ms = 600 + Math.floor(Math.random() * 600);
  const shouldFail = Math.random() < 0.25;

  return new Promise((resolve, reject) => {
    currentTimerId = setTimeout(() => {
      currentTimerId = null;

      // Se não for o job atual, ignora (cancelamento lógico)
      if (jobId !== currentJobId) return;

      if (shouldFail) reject(new Error('Falha simulada'));
      else resolve({ jobId, ms, data: ['A', 'B', 'C'] });
    }, ms);
  });
}

async function startLoad() {
  if (!hasDom) return;

  // Cancela operação anterior e inicia nova
  cancelCurrent();
  currentJobId++;
  const jobId = currentJobId;

  setUi('loading');

  try {
    const res = await fakeRequest(jobId);

    // Se outro job iniciou no meio, ignore
    if (jobId !== currentJobId) return;

    setUi('success', res);
  } catch (e) {
    if (jobId !== currentJobId) return;
    setUi('error', e);
  }
}

function onCancel() {
  cancelCurrent();
  currentJobId++; // invalida qualquer resultado pendente
  setUi('idle');
}

if (hasDom) {
  btnLoad.addEventListener('click', startLoad);
  btnCancel.addEventListener('click', onCancel);
  setUi('idle');
  console.log('[async-ui] pronto');
}
